import type { z } from "zod";

/**
 * Configuration for a content type defined by the developer.
 *
 * Field types are now specified directly in the Zod schema via .meta():
 * @example
 * ```typescript
 * const ProductSchema = z.object({
 *   description: z.string().meta({ fieldType: "textarea" }),
 *   image: z.string().optional().meta({ fieldType: "file" }),
 * });
 * ```
 */
export interface ContentTypeConfig {
	/** Display name for the content type (e.g., "Product", "Testimonial") */
	name: string;
	/** URL-friendly slug (e.g., "product", "testimonial") */
	slug: string;
	/** Optional description shown in the admin UI */
	description?: string;
	/** Zod schema defining the content type's fields. Use .meta({ fieldType: "..." }) for field type overrides. */
	schema: z.ZodObject<z.ZodRawShape>;
}

/**
 * Content type stored in the database
 */
export type ContentType = {
	id: string;
	/** Display name */
	name: string;
	/** URL-friendly slug - unique identifier */
	slug: string;
	/** Optional description */
	description?: string;
	/** JSON Schema representation of the Zod schema (stringified) */
	jsonSchema: string;
	/** @deprecated Legacy field config - now embedded in jsonSchema. Kept for backwards compat. */
	fieldConfig?: string;
	/** AutoForm schema version. 1 = legacy (separate fieldConfig), 2 = unified (fieldType in jsonSchema) */
	autoFormVersion?: number;
	createdAt: Date;
	updatedAt: Date;
};

/**
 * Content item stored in the database
 */
export type ContentItem = {
	id: string;
	/** Reference to the content type */
	contentTypeId: string;
	/** URL-friendly slug - unique within content type */
	slug: string;
	/** JSON data matching the content type's schema (stringified) */
	data: string;
	/** Optional author ID for tracking who created/modified */
	authorId?: string;
	createdAt: Date;
	updatedAt: Date;
};

/**
 * Content item with its content type joined
 */
export type ContentItemWithType = ContentItem & {
	contentType?: ContentType;
};

/**
 * Content relation stored in the database (junction table)
 * Links source content items to target content items for relationship fields
 */
export type ContentRelation = {
	id: string;
	/** The content item that has the relation field */
	sourceId: string;
	/** The content item being referenced */
	targetId: string;
	/** The field name in the source content type schema (e.g., "categoryIds") */
	fieldName: string;
	createdAt: Date;
};

// ========== Relation Field Types ==========

/**
 * Configuration for a relation field in schema metadata.
 * Use with .meta({ fieldType: "relation", relation: {...} })
 *
 * The schema stores relation values as simple `{ id: string }` references.
 * When `creatable: true`, the frontend sends `{ _new: true, data: {...} }`
 * which the API processes before validation - creating new items and
 * converting them to ID references.
 *
 * @example
 * ```typescript
 * const ResourceSchema = z.object({
 *   // Simple array of ID references - API handles _new items before validation
 *   categoryIds: z.array(z.object({ id: z.string() })).default([]).meta({
 *     fieldType: "relation",
 *     relation: {
 *       type: "manyToMany",
 *       targetType: "category",
 *       displayField: "name",
 *       creatable: true,
 *     },
 *   }),
 * });
 * ```
 */
export interface RelationConfig {
	/** Relation type */
	type: "belongsTo" | "hasMany" | "manyToMany";
	/** Target content type slug */
	targetType: string;
	/** Field to display in the dropdown (e.g., "name", "title") */
	displayField: string;
	/** Allow creating new items inline via modal (default: false) */
	creatable?: boolean;
}

/**
 * Value for a relation field - either a reference to existing item or a new item to create.
 *
 * @example
 * ```typescript
 * // Reference to existing item
 * const existing: RelationValue = { id: "abc123" };
 *
 * // New item to create on save
 * const newItem: RelationValue = {
 *   _new: true,
 *   data: { name: "New Category", description: "..." }
 * };
 * ```
 */
export type RelationValue =
	| { id: string }
	| { _new: true; data: Record<string, unknown> };

/**
 * Represents an inverse relation (content types that reference this type via belongsTo)
 */
export interface InverseRelation {
	/** The content type slug that has the belongsTo relation */
	sourceType: string;
	/** Display name of the source content type */
	sourceTypeName: string;
	/** The field name that contains the belongsTo relation */
	fieldName: string;
	/** Count of items with this relation (when itemId is provided) */
	count: number;
}

/**
 * Serialized content type for API responses (dates as strings)
 */
export interface SerializedContentType
	extends Omit<ContentType, "createdAt" | "updatedAt"> {
	createdAt: string;
	updatedAt: string;
}

/**
 * Serialized content item for API responses (dates as strings)
 */
export interface SerializedContentItem
	extends Omit<ContentItem, "createdAt" | "updatedAt"> {
	createdAt: string;
	updatedAt: string;
}

/**
 * Serialized content item with parsed data and joined content type
 * @template TData - The type of the parsed data (defaults to Record<string, unknown>)
 */
export interface SerializedContentItemWithType<TData = Record<string, unknown>>
	extends SerializedContentItem {
	/** Parsed data object (JSON.parse of data field). */
	parsedData: TData;
	/** Joined content type */
	contentType?: SerializedContentType;
	/**
	 * Populated relation data (only present when using populated endpoints/hooks).
	 * Keys are field names, values are arrays of related content items.
	 */
	_relations?: Record<string, SerializedContentItemWithType[]>;
}

/**
 * Paginated list response for content items
 * @template TData - The type of the parsed data (defaults to Record<string, unknown>)
 */
export interface PaginatedContentItems<TData = Record<string, unknown>> {
	items: SerializedContentItemWithType<TData>[];
	total: number;
	limit: number;
	offset: number;
}

/**
 * Type helper to define a map of content type slugs to their data types.
 * Use with z.infer to get the type from your Zod schemas.
 *
 * @example
 * ```typescript
 * import { z } from "zod"
 *
 * // Define your schemas
 * export const ProductSchema = z.object({
 *   name: z.string(),
 *   price: z.number(),
 * })
 *
 * export const TestimonialSchema = z.object({
 *   author: z.string(),
 *   quote: z.string(),
 * })
 *
 * // Create the type map
 * export type MyCMSTypes = {
 *   product: z.infer<typeof ProductSchema>
 *   testimonial: z.infer<typeof TestimonialSchema>
 * }
 *
 * // Use in hooks for type-safe parsedData
 * const { items } = useContent<MyCMSTypes, "product">("product")
 * // items[0].parsedData.name is typed as string
 * // items[0].parsedData.price is typed as number
 * ```
 */
export type CMSContentTypeMap = Record<string, Record<string, unknown>>;

/**
 * Context passed to CMS backend hooks
 */
export interface CMSHookContext {
	/** Content type slug */
	typeSlug: string;
	/** User ID if authenticated */
	userId?: string;
	/** Request headers */
	headers?: Headers;
}

/**
 * Hooks for customizing CMS backend behavior
 *
 * Note: Before hooks deny operations by throwing an error.
 * They cannot modify the data being saved. This ensures consistency
 * between the stored content item data and relation junction tables.
 */
export interface CMSBackendHooks {
	/** Called before creating a content item. Throw an error to deny the operation. */
	onBeforeCreate?: (
		data: Record<string, unknown>,
		context: CMSHookContext,
	) => Promise<void> | void;

	/** Called after creating a content item */
	onAfterCreate?: (
		item: SerializedContentItem,
		context: CMSHookContext,
	) => Promise<void> | void;

	/** Called before updating a content item. Throw an error to deny the operation. */
	onBeforeUpdate?: (
		id: string,
		data: Record<string, unknown>,
		context: CMSHookContext,
	) => Promise<void> | void;

	/** Called after updating a content item */
	onAfterUpdate?: (
		item: SerializedContentItem,
		context: CMSHookContext,
	) => Promise<void> | void;

	/** Called before deleting a content item. Throw an error to deny the operation. */
	onBeforeDelete?: (
		id: string,
		context: CMSHookContext,
	) => Promise<void> | void;

	/** Called after deleting a content item */
	onAfterDelete?: (id: string, context: CMSHookContext) => Promise<void> | void;

	/** Called on any CMS error */
	onError?: (
		error: Error,
		operation: "create" | "update" | "delete" | "list" | "get",
		context: CMSHookContext,
	) => Promise<void> | void;
}

/**
 * Configuration for the CMS backend plugin
 */
export interface CMSBackendConfig {
	/** Content types defined by the developer */
	contentTypes: ContentTypeConfig[];
	/** Optional hooks for customizing behavior */
	hooks?: CMSBackendHooks;
}

import { z } from "zod";

/**
 * Schema for listing content items with pagination
 */
export const listContentQuerySchema = z.object({
	slug: z.string().optional(),
	limit: z.coerce.number().min(1).max(100).optional().default(20),
	offset: z.coerce.number().min(0).optional().default(0),
});

/**
 * Schema for creating a content item
 * Note: The actual data validation is done dynamically based on the content type's schema
 */
export const createContentSchema = z.object({
	slug: z.string().min(1, "Slug is required"),
	// Use passthrough object instead of z.record(z.unknown()) due to Zod v4 bug
	data: z.object({}).passthrough(),
});

/**
 * Schema for updating a content item
 * Note: The actual data validation is done dynamically based on the content type's schema
 */
export const updateContentSchema = z.object({
	slug: z.string().min(1, "Slug is required").optional(),
	// Use passthrough object instead of z.record(z.unknown()) due to Zod v4 bug
	data: z.object({}).passthrough().optional(),
});

/**
 * Schema for content type response
 * Note: fieldConfig is no longer included - it's merged into jsonSchema during read
 */
export const contentTypeResponseSchema = z.object({
	id: z.string(),
	name: z.string(),
	slug: z.string(),
	description: z.string().nullable().optional(),
	jsonSchema: z.string(),
	createdAt: z.string(),
	updatedAt: z.string(),
});

/**
 * Schema for content item response
 */
export const contentItemResponseSchema = z.object({
	id: z.string(),
	contentTypeId: z.string(),
	slug: z.string(),
	data: z.string(),
	authorId: z.string().nullable().optional(),
	createdAt: z.string(),
	updatedAt: z.string(),
});

/**
 * Schema for content item with parsed data response
 */
export const contentItemWithDataResponseSchema =
	contentItemResponseSchema.extend({
		// Use passthrough object instead of z.record(z.unknown()) due to Zod v4 bug
		parsedData: z.object({}).passthrough(),
		contentType: contentTypeResponseSchema.optional(),
	});

/**
 * Schema for paginated content items response
 */
export const paginatedContentResponseSchema = z.object({
	items: z.array(contentItemWithDataResponseSchema),
	total: z.number(),
	limit: z.number(),
	offset: z.number(),
});

export type ListContentQuery = z.infer<typeof listContentQuerySchema>;
export type CreateContentInput = z.infer<typeof createContentSchema>;
export type UpdateContentInput = z.infer<typeof updateContentSchema>;

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";
import slug from "slug";

export function slugify(text: string, locale: string = "en"): string {
	return slug(text, { lower: true, locale });
}

export function cn(...inputs: ClassValue[]) {
	return twMerge(clsx(inputs));
}

"use client";

import { useState, useMemo, useEffect, useRef } from "react";
import { z } from "zod";
import { SteppedAutoForm } from "@/components/ui/auto-form/stepped-auto-form";
import type {
	FieldConfig,
	AutoFormInputComponentProps,
} from "@/components/ui/auto-form/types";
import { buildFieldConfigFromJsonSchema as buildFieldConfigBase } from "@/components/ui/auto-form/helpers";
import { formSchemaToZod } from "@/lib/schema-converter";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { usePluginOverrides } from "@btst/stack/context";
import type { CMSPluginOverrides } from "../../overrides";
import type { SerializedContentType, RelationConfig } from "../../../types";
import { slugify } from "../../../utils";
import { CMS_LOCALIZATION } from "../../localization";
import { CMSFileUpload } from "./file-upload";
import { RelationField } from "./relation-field";

interface ContentFormProps {
	contentType: SerializedContentType;
	initialData?: Record<string, unknown>;
	initialSlug?: string;
	isEditing?: boolean;
	onSubmit: (data: {
		slug: string;
		data: Record<string, unknown>;
	}) => Promise<void>;
	onCancel?: () => void;
}

/**
 * Build field configuration for AutoForm with CMS-specific file upload handling.
 *
 * Uses the shared buildFieldConfigFromJsonSchema from auto-form/helpers as a base,
 * then adds special handling for "file" fieldType to inject CMSFileUpload component
 * ONLY if no custom component is provided via fieldComponents.
 *
 * @param jsonSchema - The JSON Schema from the content type (with fieldType embedded in properties)
 * @param uploadImage - The uploadImage function from overrides (for file fields)
 * @param fieldComponents - Custom field components from overrides
 */
interface JsonSchemaProperty {
	fieldType?: string;
	relation?: RelationConfig;
	[key: string]: unknown;
}

function buildFieldConfigFromJsonSchema(
	jsonSchema: Record<string, unknown>,
	uploadImage?: (file: File) => Promise<string>,
	fieldComponents?: Record<
		string,
		React.ComponentType<AutoFormInputComponentProps>
	>,
): FieldConfig<Record<string, unknown>> {
	// Get base config from shared utility (handles fieldType from JSON Schema)
	const baseConfig = buildFieldConfigBase(jsonSchema, fieldComponents);

	// Apply CMS-specific handling for special fieldTypes ONLY if no custom component exists
	// Custom fieldComponents take priority - don't override if user provided one
	const properties = jsonSchema.properties as Record<
		string,
		JsonSchemaProperty
	>;

	if (!properties) return baseConfig;

	for (const [key, prop] of Object.entries(properties)) {
		// Handle "file" fieldType when there's NO custom component for "file"
		if (prop.fieldType === "file" && !fieldComponents?.["file"]) {
			// Use CMSFileUpload as the default file component
			if (!uploadImage) {
				// Show a clear error message if uploadImage is not provided
				baseConfig[key] = {
					...baseConfig[key],
					fieldType: () => (
						<div className="rounded-md border border-destructive bg-destructive/10 p-3 text-sm text-destructive">
							File upload requires an <code>uploadImage</code> function in CMS
							overrides.
						</div>
					),
				};
			} else {
				baseConfig[key] = {
					...baseConfig[key],
					fieldType: (props: AutoFormInputComponentProps) => (
						<CMSFileUpload {...props} uploadImage={uploadImage} />
					),
				};
			}
		}

		// Handle "relation" fieldType when there's NO custom component for "relation"
		if (
			prop.fieldType === "relation" &&
			prop.relation &&
			!fieldComponents?.["relation"]
		) {
			const relationConfig = prop.relation;
			baseConfig[key] = {
				...baseConfig[key],
				fieldType: (props: AutoFormInputComponentProps) => (
					<RelationField {...props} relation={relationConfig} />
				),
			};
		}
	}

	return baseConfig;
}

/**
 * Determine the first string field in the schema for slug auto-generation
 */
function findSlugSourceField(
	jsonSchema: Record<string, unknown>,
): string | null {
	const properties = jsonSchema.properties as Record<string, { type?: string }>;
	if (!properties) return null;

	// Look for common name fields first
	const priorityFields = ["name", "title", "heading", "label"];
	for (const field of priorityFields) {
		if (properties[field]?.type === "string") {
			return field;
		}
	}

	// Fall back to first string field
	for (const [key, value] of Object.entries(properties)) {
		if (value.type === "string") {
			return key;
		}
	}

	return null;
}

export function ContentForm({
	contentType,
	initialData = {},
	initialSlug = "",
	isEditing = false,
	onSubmit,
	onCancel,
}: ContentFormProps) {
	const {
		localization: customLocalization,
		uploadImage,
		fieldComponents,
	} = usePluginOverrides<CMSPluginOverrides>("cms");
	const localization = { ...CMS_LOCALIZATION, ...customLocalization };

	const [slug, setSlug] = useState(initialSlug);
	const [slugManuallyEdited, setSlugManuallyEdited] = useState(isEditing);
	const [isSubmitting, setIsSubmitting] = useState(false);
	const [formData, setFormData] =
		useState<Record<string, unknown>>(initialData);
	const [slugError, setSlugError] = useState<string | null>(null);
	const [submitError, setSubmitError] = useState<string | null>(null);

	// Track if we've already synced prefill data to avoid overwriting user input
	const hasSyncedPrefillRef = useRef(false);

	// Sync formData with initialData when it changes
	// This handles both:
	// 1. Editing mode: always sync when item data is loaded (isEditing=true)
	// 2. Create mode: only sync prefill data ONCE to avoid overwriting user input
	// useState only uses the initial value on mount, so we need this effect for updates
	useEffect(() => {
		const hasData = Object.keys(initialData).length > 0;
		// In edit mode, always sync (user is loading existing data)
		// In create mode, only sync prefill data once
		const shouldSync = hasData && (isEditing || !hasSyncedPrefillRef.current);

		if (shouldSync) {
			setFormData(initialData);
			if (!isEditing) {
				hasSyncedPrefillRef.current = true;
			}
		}
	}, [initialData, isEditing]);

	// Also sync slug when initialSlug changes
	useEffect(() => {
		if (isEditing && initialSlug) {
			setSlug(initialSlug);
		}
	}, [initialSlug, isEditing]);

	// Parse JSON Schema (now includes fieldType embedded in properties)
	const jsonSchema = useMemo(() => {
		try {
			return JSON.parse(contentType.jsonSchema) as Record<string, unknown>;
		} catch {
			return {};
		}
	}, [contentType.jsonSchema]);

	// Convert JSON Schema to Zod schema using formSchemaToZod utility
	// This properly handles date fields (format: "date-time") and min/max date constraints
	const zodSchema = useMemo(() => {
		try {
			return formSchemaToZod(jsonSchema);
		} catch {
			return z.object({});
		}
	}, [jsonSchema]);

	// Build field config for AutoForm (fieldType is now embedded in jsonSchema)
	const fieldConfig = useMemo(
		() =>
			buildFieldConfigFromJsonSchema(jsonSchema, uploadImage, fieldComponents),
		[jsonSchema, uploadImage, fieldComponents],
	);

	// Find the field to use for slug auto-generation
	const slugSourceField = useMemo(
		() => findSlugSourceField(jsonSchema),
		[jsonSchema],
	);

	// Handle form value changes for slug auto-generation
	const handleValuesChange = (values: Record<string, unknown>) => {
		setFormData(values);

		// Auto-generate slug from source field if not manually edited
		if (!isEditing && !slugManuallyEdited && slugSourceField) {
			const sourceValue = values[slugSourceField];
			if (typeof sourceValue === "string" && sourceValue.trim()) {
				setSlug(slugify(sourceValue));
			}
		}
	};

	// Handle form submission
	const handleSubmit = async (data: Record<string, unknown>) => {
		setSlugError(null);
		setSubmitError(null);

		if (!slug.trim()) {
			setSlugError("Slug is required");
			return;
		}

		setIsSubmitting(true);
		try {
			await onSubmit({ slug, data });
		} catch (error) {
			const message =
				error instanceof Error ? error.message : localization.CMS_TOAST_ERROR;
			setSubmitError(message);
		} finally {
			setIsSubmitting(false);
		}
	};

	return (
		<div className="space-y-6">
			{/* Slug field */}
			<div className="space-y-2">
				<div className="flex items-center gap-2">
					<Label htmlFor="slug">{localization.CMS_LABEL_SLUG}</Label>
					{!isEditing && (
						<Badge variant="outline" className="text-xs">
							{slugManuallyEdited
								? localization.CMS_EDITOR_SLUG_MANUAL
								: localization.CMS_EDITOR_SLUG_AUTO}
						</Badge>
					)}
				</div>
				<Input
					id="slug"
					value={slug}
					onChange={(e) => {
						setSlug(e.target.value);
						setSlugError(null);
						if (!isEditing) {
							setSlugManuallyEdited(true);
						}
					}}
					disabled={isEditing}
					placeholder={
						slugSourceField
							? `Auto-generated from ${slugSourceField}`
							: "Enter slug..."
					}
				/>
				{slugError && <p className="text-sm text-destructive">{slugError}</p>}
				<p className="text-sm text-muted-foreground">
					{localization.CMS_LABEL_SLUG_DESCRIPTION}
				</p>
			</div>

			{/* Submit error message */}
			{submitError && (
				<div className="rounded-md border border-destructive/50 bg-destructive/10 p-3">
					<p className="text-sm text-destructive">{submitError}</p>
				</div>
			)}

			{/* Dynamic form from Zod schema */}
			{/* Uses SteppedAutoForm which automatically handles both single-step and multi-step content types */}
			<SteppedAutoForm
				formSchema={zodSchema as z.ZodObject<any, any>}
				values={formData as any}
				onValuesChange={handleValuesChange as any}
				onSubmit={handleSubmit as any}
				fieldConfig={fieldConfig as any}
				isSubmitting={isSubmitting}
				submitButtonText={
					isSubmitting
						? localization.CMS_STATUS_SAVING
						: localization.CMS_BUTTON_SAVE
				}
			>
				{onCancel && (
					<button
						type="button"
						onClick={onCancel}
						className="px-4 py-2 text-sm text-muted-foreground hover:text-foreground"
					>
						{localization.CMS_BUTTON_CANCEL}
					</button>
				)}
			</SteppedAutoForm>
		</div>
	);
}

"use client";

import { useState, useCallback, useEffect, type ChangeEvent } from "react";
import { toast } from "sonner";
import type { AutoFormInputComponentProps } from "@/components/ui/auto-form/types";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import {
	FormControl,
	FormItem,
	FormMessage,
} from "@/components/ui/form";
import { Trash2, Loader2 } from "lucide-react";
import AutoFormLabel from "@/components/ui/auto-form/common/label";
import AutoFormTooltip from "@/components/ui/auto-form/common/tooltip";

/**
 * Props for the CMSFileUpload component
 */
export interface CMSFileUploadProps extends AutoFormInputComponentProps {
	/**
	 * Function to upload an image file and return the URL.
	 * This is required - consumers must provide an upload implementation.
	 */
	uploadImage: (file: File) => Promise<string>;
}

/**
 * Default file upload component for CMS image fields.
 *
 * This component:
 * - Accepts image files via file input
 * - Uses the required uploadImage prop to upload and get a URL
 * - Shows a preview of the uploaded image
 * - Allows removing the uploaded image
 *
 * You can use this component directly in your fieldComponents override,
 * or create your own custom component using this as a reference.
 *
 * @example
 * ```tsx
 * // Use the default component with your upload function
 * fieldComponents: {
 *   file: (props) => (
 *     <CMSFileUpload {...props} uploadImage={myUploadFn} />
 *   ),
 * }
 * ```
 */
export function CMSFileUpload({
	label,
	isRequired,
	fieldConfigItem,
	fieldProps,
	field,
	uploadImage,
}: CMSFileUploadProps) {
	// Exclude showLabel and value from props spread
	// File inputs cannot have their value set programmatically (browser security)
	const {
		showLabel: _showLabel,
		value: _value,
		...safeFieldProps
	} = fieldProps;
	const showLabel = _showLabel === undefined ? true : _showLabel;
	const [isUploading, setIsUploading] = useState(false);
	const [previewUrl, setPreviewUrl] = useState<string | null>(
		field.value || null,
	);

	useEffect(() => {
		const normalizedValue = field.value || null;
		if (normalizedValue !== previewUrl) {
			setPreviewUrl(normalizedValue);
		}
	}, [field.value, previewUrl]);

	const handleFileChange = useCallback(
		async (e: ChangeEvent<HTMLInputElement>) => {
			const file = e.target.files?.[0];
			if (!file) return;

			// Check if it's an image
			if (!file.type.startsWith("image/")) {
				toast.error("Please select an image file");
				return;
			}

			setIsUploading(true);
			try {
				const url = await uploadImage(file);
				setPreviewUrl(url);
				field.onChange(url);
			} catch (error) {
				console.error("Image upload failed:", error);
				toast.error("Failed to upload image");
			} finally {
				setIsUploading(false);
			}
		},
		[field, uploadImage],
	);

	const handleRemove = useCallback(() => {
		setPreviewUrl(null);
		field.onChange("");
	}, [field]);

	return (
		<FormItem>
			{showLabel && (
				<AutoFormLabel
					label={fieldConfigItem?.label || label}
					isRequired={isRequired}
				/>
			)}
			{!previewUrl && (
				<FormControl>
					<div className="relative">
						<Input
							type="file"
							accept="image/*"
							{...safeFieldProps}
							onChange={handleFileChange}
							disabled={isUploading}
							className="cursor-pointer"
							data-testid="image-upload-input"
						/>
						{isUploading && (
							<div className="absolute inset-0 flex items-center justify-center bg-background/80">
								<Loader2 className="h-4 w-4 animate-spin" />
							</div>
						)}
					</div>
				</FormControl>
			)}
			{previewUrl && (
				<div className="flex items-center gap-2">
					<div className="relative h-20 w-20 overflow-hidden rounded-md border">
						<img
							src={previewUrl}
							alt="Preview"
							className="h-full w-full object-cover"
							data-testid="image-preview"
						/>
					</div>
					<Button
						type="button"
						variant="outline"
						size="sm"
						onClick={handleRemove}
						className="flex items-center gap-1"
						data-testid="remove-image-button"
					>
						<Trash2 className="h-4 w-4" />
						Remove
					</Button>
				</div>
			)}
			<AutoFormTooltip fieldConfigItem={fieldConfigItem} />
			<FormMessage />
		</FormItem>
	);
}

"use client";

import { useState, useCallback, useMemo } from "react";
import { useContent, useCreateContent } from "@btst/stack/plugins/cms/client/hooks";
import MultipleSelector from "@/components/ui/multi-select";
import type { Option } from "@/components/ui/multi-select";
import { Button } from "@/components/ui/button";
import { Plus, X } from "lucide-react";
import {
	Dialog,
	DialogContent,
	DialogHeader,
	DialogTitle,
	DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import type { AutoFormInputComponentProps } from "@/components/ui/auto-form/types";
import type { RelationConfig } from "../../../types";

interface RelationFieldProps extends AutoFormInputComponentProps {
	relation: RelationConfig;
}

/**
 * A form field component for handling CMS content relationships.
 * Supports selecting existing items and optionally creating new items inline.
 *
 * Handles two value formats:
 * - belongsTo: single object { id: string } or undefined
 * - hasMany/manyToMany: array of { id: string }
 */
export function RelationField({
	field,
	fieldConfigItem,
	label,
	isRequired,
	relation,
}: RelationFieldProps) {
	const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
	const [newItemName, setNewItemName] = useState("");
	const [newItemDescription, setNewItemDescription] = useState("");
	const [createError, setCreateError] = useState<string | null>(null);

	// For belongsTo (single relation), we only allow one selection
	const isSingleSelect = relation.type === "belongsTo";

	// Fetch available items from the target content type
	const { items: availableItems, isLoading } = useContent(relation.targetType, {
		limit: 100, // Load a good chunk for the dropdown
	});

	// Mutation for creating new items
	const createMutation = useCreateContent(relation.targetType);

	// Normalize the field value to an array for internal use
	// belongsTo stores as single object { id }, hasMany/manyToMany store as array
	const normalizedValue = useMemo((): Array<{ id: string }> => {
		if (!field.value) return [];

		if (isSingleSelect) {
			// belongsTo: value is { id: string } or undefined
			const singleValue = field.value as { id?: string } | undefined;
			if (singleValue && singleValue.id) {
				return [{ id: singleValue.id }];
			}
			return [];
		}

		// hasMany/manyToMany: value is array
		return (field.value as Array<{ id: string }>) || [];
	}, [field.value, isSingleSelect]);

	// Convert normalized value to Option[] for MultipleSelector
	const selectedOptions: Option[] = normalizedValue
		.map((v) => {
			const item = availableItems.find((item) => item.id === v.id);
			if (item) {
				const displayValue =
					(item.parsedData as Record<string, unknown>)?.[
						relation.displayField
					] || item.slug;
				return {
					value: item.id,
					label: String(displayValue),
				};
			}
			// Item not found in loaded items - show ID
			return { value: v.id, label: `ID: ${v.id.slice(0, 8)}...` };
		})
		.filter(Boolean);

	// Convert available items to options
	const options: Option[] = availableItems.map((item) => {
		const displayValue =
			(item.parsedData as Record<string, unknown>)?.[relation.displayField] ||
			item.slug;
		return {
			value: item.id,
			label: String(displayValue),
		};
	});

	// Handle selection change - convert back to appropriate format
	const handleChange = useCallback(
		(newOptions: Option[]) => {
			if (isSingleSelect) {
				// belongsTo: store as single object or undefined
				if (newOptions.length > 0) {
					field.onChange({ id: newOptions[0]!.value });
				} else {
					field.onChange(undefined);
				}
			} else {
				// hasMany/manyToMany: store as array
				const newValue = newOptions.map((opt) => ({ id: opt.value }));
				field.onChange(newValue);
			}
		},
		[field, isSingleSelect],
	);

	// Handle creating a new item
	const handleCreateItem = async () => {
		if (!newItemName.trim()) return;

		setCreateError(null);
		try {
			const result = await createMutation.mutateAsync({
				slug: newItemName.toLowerCase().replace(/\s+/g, "-"),
				data: {
					[relation.displayField]: newItemName,
					description: newItemDescription || undefined,
				} as Record<string, unknown>,
			});

			// Add the new item to the selection
			if (isSingleSelect) {
				// belongsTo: replace with new item
				field.onChange({ id: result.id });
			} else {
				// hasMany/manyToMany: append to array
				const newValue = [...normalizedValue, { id: result.id }];
				field.onChange(newValue);
			}

			// Reset and close dialog
			setNewItemName("");
			setNewItemDescription("");
			setIsCreateDialogOpen(false);
		} catch (error) {
			const message =
				error instanceof Error
					? error.message
					: "Failed to create item. Please try again.";
			setCreateError(message);
		}
	};

	// Handle removing an item
	const handleRemove = useCallback(
		(idToRemove: string) => {
			if (isSingleSelect) {
				// belongsTo: clear the value
				field.onChange(undefined);
			} else {
				// hasMany/manyToMany: filter out the item
				const newValue = normalizedValue.filter((v) => v.id !== idToRemove);
				field.onChange(newValue);
			}
		},
		[normalizedValue, field, isSingleSelect],
	);

	return (
		<div className="space-y-2">
			<Label>
				{label}
				{isRequired && <span className="text-destructive ml-1">*</span>}
			</Label>

			<div className="flex gap-2">
				<div className="flex-1">
					<MultipleSelector
						value={selectedOptions}
						onChange={handleChange}
						options={options}
						placeholder={
							isLoading
								? "Loading..."
								: `Select ${relation.targetType}${isSingleSelect ? "" : "(s)"}...`
						}
						disabled={isLoading}
						hidePlaceholderWhenSelected
						emptyIndicator={
							<p className="text-center text-sm text-muted-foreground py-4">
								No {relation.targetType} items found
							</p>
						}
						maxSelected={isSingleSelect ? 1 : undefined}
						className="min-h-10"
					/>
				</div>

				{/* Create new item button/dialog */}
				{relation.creatable && (
					<Dialog
						open={isCreateDialogOpen}
						onOpenChange={setIsCreateDialogOpen}
					>
						<DialogTrigger asChild>
							<Button type="button" variant="outline" size="icon">
								<Plus className="h-4 w-4" />
							</Button>
						</DialogTrigger>
						<DialogContent>
							<DialogHeader>
								<DialogTitle>Create New {relation.targetType}</DialogTitle>
							</DialogHeader>
							<div className="space-y-4 py-4">
								{createError && (
									<p className="text-sm text-destructive">{createError}</p>
								)}
								<div className="space-y-2">
									<Label htmlFor="newItemName">
										{relation.displayField.charAt(0).toUpperCase() +
											relation.displayField.slice(1)}
									</Label>
									<Input
										id="newItemName"
										value={newItemName}
										onChange={(e) => setNewItemName(e.target.value)}
										placeholder={`Enter ${relation.displayField}...`}
									/>
								</div>
								<div className="space-y-2">
									<Label htmlFor="newItemDescription">
										Description (optional)
									</Label>
									<Textarea
										id="newItemDescription"
										value={newItemDescription}
										onChange={(e) => setNewItemDescription(e.target.value)}
										placeholder="Enter description..."
										rows={3}
									/>
								</div>
								<div className="flex justify-end gap-2">
									<Button
										type="button"
										variant="outline"
										onClick={() => setIsCreateDialogOpen(false)}
									>
										Cancel
									</Button>
									<Button
										type="button"
										onClick={handleCreateItem}
										disabled={!newItemName.trim() || createMutation.isPending}
									>
										{createMutation.isPending ? "Creating..." : "Create"}
									</Button>
								</div>
							</div>
						</DialogContent>
					</Dialog>
				)}
			</div>

			{/* Show selected items as removable badges */}
			{selectedOptions.length > 0 && (
				<div className="flex flex-wrap gap-1 mt-2">
					{selectedOptions.map((opt) => (
						<div
							key={opt.value}
							className="inline-flex items-center gap-1 px-2 py-1 text-xs rounded-md bg-secondary text-secondary-foreground"
						>
							<span>{opt.label}</span>
							<button
								type="button"
								onClick={() => handleRemove(opt.value)}
								className="hover:text-destructive"
							>
								<X className="h-3 w-3" />
							</button>
						</div>
					))}
				</div>
			)}

			{fieldConfigItem?.description && (
				<p className="text-sm text-muted-foreground">
					{fieldConfigItem.description}
				</p>
			)}
		</div>
	);
}

"use client";

import { useState } from "react";
